import React, { useState, useEffect } from "react";
import { useHistory, useParams } from "react-router-dom";
import axios from "axios";

import Form from "react-bootstrap/Form";
import Button from "react-bootstrap/Button";

import "./Vote.css";
function Vote() {
  const [radio, setRadio] = useState("");
  const [fields, setFields] = useState({ question: "", options: [""] });
  const history = useHistory();

  const { id } = useParams();

  useEffect(() => {
    axios
      .get(`/poll/${id}`)
      .then((res) => {
        const options = res.data.poll.options;
        setFields({ question: res.data.poll.question, options: options });
      })
      .catch((error) => {
        console.log(error);
      });
  }, [id]);

  function votePoll() {
    axios
      .post(`/poll/${id}`, { radio })
      .then((res) => {
        console.log(res);
      })
      .catch((error) => {
        console.log(error);
      });
  }

  function handleSubmit(e) {
    e.preventDefault();
    votePoll();
    return history.push(`/results/${id}`);
  }
  function handleRadioChange(event) {
    setRadio(event.target.value);
  }
  return (
    <div className="vote-page-wrapper">
      <div className="vote-poll-wrapper">
        <div className="vote-poll-question">
          <h1>{fields.question}</h1>
        </div>
        <Form onSubmit={(event) => handleSubmit(event)}>
          <Form.Group>
            <div
              className="vote-poll-options d-flex flex-column"
              onChange={(event) => {
                handleRadioChange(event);
              }}
            >
              {fields.options.map((option, idx) => {
                return (
                  <Form.Label
                    key={`${option._id}-${idx}`}
                    className={
                      radio === `${option._id}`
                        ? "poll-option selected"
                        : "poll-option"
                    }
                  >
                    <Form.Check name="option" value={option._id} type="radio" />
                    <span>{option.value}</span>
                  </Form.Label>
                );
              })}
            </div>
            <Button type="submit" variant="success">
              Submit
            </Button>
          </Form.Group>
        </Form>
      </div>
    </div>
  );
}

export default Vote;